use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;

pub struct VectorDB {
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.vectors.write().unwrap();
        guard.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut guard = self.vectors.write().unwrap();
        guard.extend(vectors);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let guard = self.vectors.read().unwrap();
        if top_k == 0 || guard.is_empty() {
            return Vec::new();
        }
        let mut results: Vec<SearchResult> = guard
            .iter()
            .map(|(id, v)| SearchResult {
                id: *id,
                distance: l2_distance(vector, v),
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        let k = top_k as usize;
        if results.len() > k {
            results.truncate(k);
        }
        results
    }
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    let len = a.len().min(b.len());
    for i in 0..len {
        let diff = a[i] as f64 - b[i] as f64;
        sum += diff * diff;
    }
    sum
}

