use crate::api::*;
use crate::distance::l2_distance_f32;
use ordered_float::OrderedFloat;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;

const DIM: usize = 128;

struct VectorData {
    ids: Vec<u64>,
    vectors: Vec<f32>,
}

pub struct VectorDB {
    data: RwLock<VectorData>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(VectorData {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.data.write();
        guard.ids.push(id);
        guard.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut guard = self.data.write();
        guard.ids.reserve(count);
        guard.vectors.reserve(count * DIM);
        for (id, vector) in vectors {
            guard.ids.push(id);
            guard.vectors.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let k = top_k as usize;
        if k == 0 {
            return Vec::new();
        }
        let guard = self.data.read();
        if guard.ids.is_empty() {
            return Vec::new();
        }
        let ids = &guard.ids;
        let vectors = &guard.vectors;

        let heap = vectors
            .par_chunks_exact(DIM)
            .enumerate()
            .fold(
                || BinaryHeap::<(OrderedFloat<f32>, u64)>::with_capacity(k + 1),
                |mut heap, (idx, chunk)| {
                    let dist = l2_distance_f32(vector, chunk);
                    push_heap(&mut heap, dist, ids[idx], k);
                    heap
                },
            )
            .reduce(
                || BinaryHeap::<(OrderedFloat<f32>, u64)>::with_capacity(k + 1),
                |mut heap, other| {
                    for (dist, id) in other.into_iter() {
                        push_heap(&mut heap, dist.0, id, k);
                    }
                    heap
                },
            );

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|(dist, id)| SearchResult {
                id,
                distance: dist.0 as f64,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}

#[inline]
fn push_heap(heap: &mut BinaryHeap<(OrderedFloat<f32>, u64)>, dist: f32, id: u64, k: usize) {
    if heap.len() < k {
        heap.push((OrderedFloat(dist), id));
    } else if let Some(top) = heap.peek() {
        if dist < top.0 .0 {
            heap.pop();
            heap.push((OrderedFloat(dist), id));
        }
    }
}

use std::arch::x86_64::*;

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_f32(a, b) as f64
}

#[inline]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            unsafe {
                return l2_distance_avx512(a, b);
            }
        }
        if is_x86_feature_detected!("avx2") {
            unsafe {
                return l2_distance_avx2(a, b);
            }
        }
    }
    l2_distance_scalar(a, b)
}

#[inline]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    let len = a.len().min(b.len());
    let mut i = 0;
    while i < len {
        let diff = a[i] - b[i];
        sum += diff * diff;
        i += 1;
    }
    sum
}

#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = _mm512_setzero_ps();
    let len = a.len();
    let mut i = 0;
    while i + 16 <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        let prod = _mm512_mul_ps(diff, diff);
        sum = _mm512_add_ps(sum, prod);
        i += 16;
    }
    let mut total = _mm512_reduce_add_ps(sum);
    while i < len {
        let diff = *a.get_unchecked(i) - *b.get_unchecked(i);
        total += diff * diff;
        i += 1;
    }
    total
}

#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = _mm256_setzero_ps();
    let len = a.len();
    let mut i = 0;
    while i + 8 <= len {
        let va = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(va, vb);
        let prod = _mm256_mul_ps(diff, diff);
        sum = _mm256_add_ps(sum, prod);
        i += 8;
    }
    let mut tmp = [0.0f32; 8];
    _mm256_storeu_ps(tmp.as_mut_ptr(), sum);
    let mut total = tmp.iter().sum::<f32>();
    while i < len {
        let diff = *a.get_unchecked(i) - *b.get_unchecked(i);
        total += diff * diff;
        i += 1;
    }
    total
}

