                vectors: Vec::new(),
                short_vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.data.write();
        guard.ids.push(id);
        guard.vectors.extend_from_slice(&vector);
        for &dim in SHORT_DIMS.iter() {
            guard.short_vectors.push(vector[dim]);
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut guard = self.data.write();
        guard.ids.reserve(count);
        guard.vectors.reserve(count * DIM);
        guard.short_vectors.reserve(count * SDIM);
        for (id, vector) in vectors {
            guard.ids.push(id);
            guard.vectors.extend_from_slice(&vector);
            for &dim in SHORT_DIMS.iter() {
                guard.short_vectors.push(vector[dim]);
            }
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let k = top_k as usize;
        if k == 0 {
            return Vec::new();
        }
        let guard = self.data.read();
        if guard.ids.is_empty() {
            return Vec::new();
        }
        let ids = &guard.ids;
        let vectors = &guard.vectors;
        let short_vectors = &guard.short_vectors;

        let mut query_short = [0.0f32; SDIM];
        for (i, &dim) in SHORT_DIMS.iter().enumerate() {
            query_short[i] = vector[dim];
        }

        let candidate_limit = CANDIDATES.max(k);
        let mut heap: BinaryHeap<(OrderedFloat<f32>, usize)> =
            BinaryHeap::with_capacity(candidate_limit + 1);

        for (idx, chunk) in short_vectors.chunks_exact(SDIM).enumerate() {
            let dist = l2_distance_short(&query_short, chunk);
            if heap.len() < candidate_limit {
                heap.push((OrderedFloat(dist), idx));
            } else if let Some(top) = heap.peek() {
                if dist < top.0 .0 {
                    heap.pop();
                    heap.push((OrderedFloat(dist), idx));
                }
            }
        }

        let mut topk = TopK::new(k);
        for (_dist, idx) in heap.into_iter() {
            let start = idx * DIM;
            let end = start + DIM;
            let dist = l2_distance_f32(vector, &vectors[start..end]);
            topk.consider(ids[idx], dist);
        }

        topk.into_results()
    }
}

#[inline]
fn l2_distance_short(a: &[f32; SDIM], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for i in 0..SDIM {
        let diff = a[i] - b[i];
        sum += diff * diff;
    }
    sum
}

